const STORAGE_KEY = 'nguucat_reception_data'

// ─── Store ────────────────────────────────────────────────────────────

export const useReceptionStore = defineStore('reception', () => {
  const reservations = ref<ReceptionReservation[]>([])
  const activeSessions = ref<ActiveSession[]>([])
  const lastUpdated = ref<string | null>(null)
  const isLoaded = ref(false)

  // ─── Getters ───────────────────────────────────────────────────────

  const todayReservations = computed(() => {
    const today = todayStr()
    return reservations.value.filter((r) => r.reservationDate === today)
  })

  /** Reservations that still need a table assigned (not cancelled/completed, no tableCode). */
  const waitingReservations = computed(() =>
    reservations.value.filter(
      (r) =>
        r.status !== 'CANCELLED' &&
        r.status !== 'COMPLETED' &&
        !r.tableCode,
    ),
  )

  /** Reservations that already have a table assigned and are dining. */
  const seatedReservations = computed(() =>
    reservations.value.filter((r) => r.status === 'SEATED' || (r.tableCode && r.status === 'CONFIRMED')),
  )

  const pendingCount = computed(
    () => todayReservations.value.filter((r) => r.status === 'PENDING').length,
  )

  const confirmedCount = computed(
    () => todayReservations.value.filter((r) => r.status === 'CONFIRMED').length,
  )

  const seatedCount = computed(
    () => todayReservations.value.filter((r) => r.status === 'SEATED').length,
  )

  const completedCount = computed(
    () => todayReservations.value.filter((r) => r.status === 'COMPLETED').length,
  )

  const cancelledCount = computed(
    () => todayReservations.value.filter((r) => r.status === 'CANCELLED').length,
  )

  // ─── Persistence ───────────────────────────────────────────────────

  function persistToStorage() {
    try {
      lastUpdated.value = nowIso()
      localStorage.setItem(
        STORAGE_KEY,
        JSON.stringify({
          reservations: reservations.value,
          activeSessions: activeSessions.value,
          lastUpdated: lastUpdated.value,
        }),
      )
    } catch (e) {
      console.error('[receptionStore] persist failed:', e)
    }
  }

  function loadFromStorage(): boolean {
    try {
      const stored = localStorage.getItem(STORAGE_KEY)
      if (stored) {
        const data = JSON.parse(stored)
        reservations.value = data.reservations || []
        activeSessions.value = data.activeSessions || []
        lastUpdated.value = data.lastUpdated || null
        return reservations.value.length > 0
      }
    } catch (e) {
      console.error('[receptionStore] load from storage failed:', e)
    }
    return false
  }

  // ─── Load ──────────────────────────────────────────────────────────

  async function loadReservations(force = false) {
    if (isLoaded.value && !force) return

    // 1. Try Supabase (via useReservation composable) — lazy import
    //    to avoid circular dependency if the composable ever imports
    //    this store.
    if (isSupabaseConfigured) {
      try {
        const { useReservation } = await import('@/composables/useReservation')
        const { listReservations } = useReservation()
        const today = todayStr()
        const result = await listReservations({ date: today })
        if (result.reservations && result.reservations.length > 0) {
          reservations.value = result.reservations.map(mapDbReservation)
          isLoaded.value = true
          persistToStorage()
          return
        }
      } catch (e) {
        console.warn('[receptionStore] Supabase load failed, using fallback:', e)
      }
    }

    // 2. Try localStorage
    if (loadFromStorage()) {
      isLoaded.value = true
      return
    }

    // 3. Fall back to mock data
    reservations.value = JSON.parse(JSON.stringify(MOCK_RESERVATIONS))
    isLoaded.value = true
    persistToStorage()
  }

  /** Map a Supabase `ReservationRow` (snake_case, JSONB snapshots) to our unified type. */
  function mapDbReservation(row: any): ReceptionReservation {
    const snapshot = row.customer_snapshot ?? row.customers ?? {}
    const rawTime = String(row.reservation_time ?? '').slice(0, 5)
    return {
      id: String(row.id),
      code: String(row.code ?? row.reservation_code ?? `#RES${row.id?.slice(-4)}`),
      customerName: String(snapshot.name ?? row.customer_name ?? row.guest_name ?? ''),
      customerPhone: String(snapshot.phone ?? row.customer_phone ?? row.guest_phone ?? ''),
      email: String(snapshot.email ?? row.customer_email ?? ''),
      guests: Number(row.guests ?? row.guest_count ?? row.party_size ?? 1),
      children: Number(snapshot.children ?? 0),
      reservationDate: String(row.reservation_date ?? row.date ?? todayStr()),
      reservationTime: rawTime || '12:00',
      timeSlot: deriveTimeSlot(rawTime),
      notes: typeof row.notes === 'string' ? row.notes : row.notes?.request ?? '',
      status: normalizeStatus(String(row.status ?? 'PENDING')),
      source: String(row.source ?? 'Walk-in'),
      mealType: deriveTimeSlot(rawTime) === 'morning' || deriveTimeSlot(rawTime) === 'lunch' ? 'LUNCH' : 'DINNER',
      tableCode: row.table_code ?? row.table_id ?? null,
      tableId: row.table_id ?? null,
      deposit: Number(row.deposit ?? 0),
      partyName: String(row.party_name ?? ''),
      isVip: Boolean(snapshot.is_vip ?? row.is_vip ?? false),
      createdAt: String(row.created_at ?? nowIso()),
    }
  }

  function deriveTimeSlot(time: string): 'morning' | 'lunch' | 'afternoon' | 'evening' {
    const h = parseInt(time.split(':')[0] ?? '12', 10)
    if (h < 11) return 'morning'
    if (h < 14) return 'lunch'
    if (h < 17) return 'afternoon'
    return 'evening'
  }

  // ─── CRUD ──────────────────────────────────────────────────────────

  function addReservation(
    data: Partial<ReceptionReservation>,
  ): ReceptionReservation {
    const seq = reservations.value.length + 1
    const time = data.reservationTime || '12:00'
    const newRes: ReceptionReservation = {
      id: data.id || `RES${Date.now()}`,
      code: data.code || `#RES${String(seq).padStart(3, '0')}`,
      customerName: data.customerName || '',
      customerPhone: data.customerPhone || '',
      email: data.email || '',
      guests: data.guests || 1,
      children: data.children || 0,
      reservationDate: data.reservationDate || todayStr(),
      reservationTime: time,
      timeSlot: data.timeSlot || deriveTimeSlot(time),
      notes: data.notes || '',
      status: data.status || 'PENDING',
      source: data.source || 'Walk-in',
      mealType: data.mealType || (deriveTimeSlot(time) === 'evening' || deriveTimeSlot(time) === 'afternoon' ? 'DINNER' : 'LUNCH'),
      tableCode: data.tableCode || null,
      tableId: data.tableId || null,
      deposit: data.deposit || 0,
      partyName: data.partyName || '',
      isVip: data.isVip || false,
      createdAt: nowIso(),
    }
    reservations.value.push(newRes)
    persistToStorage()
    return newRes
  }

  function updateReservation(
    id: string,
    updates: Partial<ReceptionReservation>,
  ): ReceptionReservation | null {
    const idx = reservations.value.findIndex((r) => r.id === id)
    if (idx !== -1) {
      reservations.value[idx] = { ...reservations.value[idx], ...updates }
      persistToStorage()
      return reservations.value[idx]
    }
    return null
  }

  function deleteReservation(id: string): boolean {
    const idx = reservations.value.findIndex((r) => r.id === id)
    if (idx !== -1) {
      reservations.value.splice(idx, 1)
      persistToStorage()
      return true
    }
    return false
  }

  // ─── Table Assignment ──────────────────────────────────────────────

  function assignTable(
    reservationId: string,
    tableCode: string,
    tableId?: string,
  ): ReceptionReservation | null {
    const res = reservations.value.find((r) => r.id === reservationId)
    if (!res) return null

    res.tableCode = tableCode
    res.tableId = tableId ?? tableCode
    res.status = 'SEATED'

    activeSessions.value.push({
      id: `SES${Date.now()}`,
      reservationId,
      tableCode,
      customerName: res.customerName,
      customerPhone: res.customerPhone,
      guests: res.guests,
      seatedAt: nowIso(),
    })

    persistToStorage()
    return res
  }

  function releaseTable(tableCode: string) {
    const sIdx = activeSessions.value.findIndex((s) => s.tableCode === tableCode)
    if (sIdx !== -1) {
      const session = activeSessions.value[sIdx]
      const res = reservations.value.find((r) => r.id === session.reservationId)
      if (res) {
        res.status = 'COMPLETED'
        res.tableCode = null
      }
      activeSessions.value.splice(sIdx, 1)
      persistToStorage()
    }
  }

  function getSessionByTable(tableCode: string): ActiveSession | undefined {
    return activeSessions.value.find((s) => s.tableCode === tableCode)
  }

  function getReservationByTable(tableCode: string): ReceptionReservation | undefined {
    return reservations.value.find((r) => r.tableCode === tableCode)
  }

  // ─── Reset ─────────────────────────────────────────────────────────

  function resetState() {
    reservations.value = []
    activeSessions.value = []
    lastUpdated.value = null
    isLoaded.value = false
    localStorage.removeItem(STORAGE_KEY)
  }

  function resetToMock() {
    reservations.value = JSON.parse(JSON.stringify(MOCK_RESERVATIONS))
    activeSessions.value = []
    isLoaded.value = true
    persistToStorage()
  }

  return {
    // State
    reservations,
    activeSessions,
    lastUpdated,
    isLoaded,
    // Getters
    todayReservations,
    waitingReservations,
    seatedReservations,
    pendingCount,
    confirmedCount,
    seatedCount,
    completedCount,
    cancelledCount,
    // Actions
    loadReservations,
    addReservation,
    updateReservation,
    deleteReservation,
    assignTable,
    releaseTable,
    getSessionByTable,
    getReservationByTable,
    persistToStorage,
    loadFromStorage,
    resetState,
    resetToMock,
  }
})

// File: src/stores/customerStore.ts
import { defineStore } from 'pinia';
import type {
  CustomerSession,
  Table,
  Area,
  Branch,
  MenuItem,
  MenuCategory,
  CartItem,
  Order,
  ServiceRequest,
  Feedback,
  SubCategory
} from '@/types/customer';
import { customerApiImpl } from '@/services/customerApi';
import { computeTotals } from '@/utils/packageRules';
import { isValidUUID } from '@/utils/validators';

export interface Notification {
  id: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
}

export const useCustomerStore = defineStore('customer', {
  state: () => ({
    // Session
    session: null as CustomerSession | null,
    isAuthenticated: false, // unlocked by staff passcode

    // Branch
    branches: [] as Branch[],
    selectedBranchId: null as string | null,

    // Area & Table
    areas: [] as Area[],
    selectedAreaId: null as string | null,
    tables: [] as Table[],
    selectedTable: null as Table | null,

    // Menu
    menuData: [] as MenuCategory[],
    selectedCategory: null as MenuCategory | null,
    selectedSubcategory: null as SubCategory | null,

    // Cart
    cart: [] as CartItem[],

    // Orders
    orders: [] as Order[],
    currentOrder: null as Order | null,

    // Service Requests
    serviceRequests: [] as ServiceRequest[],

    // Feedback
    feedback: null as Feedback | null,

    // UI State
    loading: false,
    currentView: 'home' as 'home' | 'menu' | 'cart' | 'history' | 'feedback',
    notifications: [] as Notification[],
    searchQuery: '',
    currentLanguage: 'vi' as 'vi' | 'en' | 'ja'
  }),

  actions: {
    // NV1: Authentication & Table Selection
    async authenticateStaff(passcode: string): Promise<boolean> {
      const res = await customerApiImpl.authenticateStaff(passcode);
      this.isAuthenticated = res.success;
      return res.success;
    },

    async loadBranches(): Promise<Branch[]> {
      const branches = await customerApiImpl.getBranches();
      this.branches = branches;
      return branches;
    },

    async loadAreas(branchId?: string): Promise<Area[]> {
      const areas = await customerApiImpl.getAreas(branchId ?? this.selectedBranchId ?? undefined);
      this.areas = areas;
      return areas;
    },

    async loadTables(areaId: string): Promise<Table[]> {
      const tables = await customerApiImpl.getTables(areaId);
      this.tables = tables;
      return tables;
    },

    async selectTable(tableId: string): Promise<boolean> {
      const res = await customerApiImpl.selectTable(tableId);
      if (res.success) {
        const table = this.tables.find(t => t.id === tableId);
        if (table) {
          this.selectedTable = table;
        }
        return true;
      }
      return false;
    },

    async confirmTable(): Promise<void> {
      if (!this.selectedTable) return;

      const newSession: CustomerSession = {
        id: `sess-${Date.now()}`,
        tableId: this.selectedTable.id,
        tableNumber: this.selectedTable.number,
        areaId: this.selectedTable.areaId,
        areaName: this.areas.find(a => a.id === this.selectedTable?.areaId)?.name || 'Khu vực',
        staffId: 'staff-uuid-001',
        startedAt: new Date(),
        status: 'active'
      };

      const session = await customerApiImpl.confirmTable(newSession);
      this.session = session;
      this.currentView = 'menu';

      // Persist session to localStorage for active session recovery
      localStorage.setItem('nguucat_customer_session', JSON.stringify(session));
      localStorage.setItem('nguucat_customer_auth', 'true');
      if (this.selectedTable) {
        localStorage.setItem('nguucat_customer_table', JSON.stringify(this.selectedTable));
      }
    },

    // NV2: Menu & Add to Cart
    async loadMenu(): Promise<void> {
      // The store exposes the same nested shape that
      // `src/data/menuData.ts` ships (categories → subcategories →
      // items). The mock file uses fake auto-counter ids
      // (`bf1390-1`, `lunch-16`, …); the live Supabase `menu_items`
      // rows have real UUIDs. We deep-clone the template, then walk
      // it and substitute each leaf item's `id` / `price` /
      // `price_display` with the DB values matched on `name`.
      //
      // Some names appear multiple times in the DB (e.g. `7UP` has
      // both a 35.000đ "à la carte" row and a 0đ "in-package" row).
      // Tie-break on price: prefer the DB row whose price matches the
      // mock item's price; if neither matches, take the first.
      const dbItems = await customerApiImpl.getRawMenuItems()
      const byName = new Map<string, Array<{ id: string; price: number; price_display?: string }>>()
      for (const it of dbItems) {
        if (!it?.name || !it?.id) continue
        const arr = byName.get(it.name) ?? []
        arr.push({ id: it.id, price: it.price, price_display: it.price_display })
        byName.set(it.name, arr)
      }
      const template = await customerApiImpl.getMenuTemplate()
      const transformed = JSON.parse(JSON.stringify(template)) as MenuCategory[]
      const pickReal = (
        name: string,
        mockPrice: number,
      ): { id: string; price: number; price_display?: string } | undefined => {
        const arr = byName.get(name)
        if (!arr || arr.length === 0) return undefined
        const exact = arr.find((r) => r.price === mockPrice)
        if (exact) return exact
        // Prefer non-zero when mock is zero, and zero when mock is non-zero.
        const dir = arr.find((r) => (mockPrice === 0 ? r.price === 0 : r.price > 0))
        return dir ?? arr[0]
      }
      const walk = (items?: MenuItem[]) => {
        if (!items) return
        for (const it of items) {
          const real = pickReal(it.name, Number(it.price ?? 0))
          if (real) {
            it.id = real.id
            it.price = real.price
            if (real.price_display) it.price_display = real.price_display
          } else {
            // No DB match found — mark as unavailable so it cannot be
            // added to cart (its mock id is not a valid UUID).
            it.is_available = false
          }
        }
      }
      for (const cat of transformed) {
        if (cat.items) walk(cat.items)
        if (cat.subcategories) {
          for (const sub of cat.subcategories) {
            walk(sub.items)
          }
        }
      }
      this.menuData = transformed
      if (transformed.length > 0) {
        this.selectedCategory = transformed[0]
        if (transformed[0].subcategories && transformed[0].subcategories.length > 0) {
          this.selectedSubcategory = transformed[0].subcategories[0]
        }
      }
    },

    selectCategory(categoryId: string): void {
      const cat = this.menuData.find(c => c.id === categoryId);
      if (cat) {
        this.selectedCategory = cat;
        if (cat.subcategories && cat.subcategories.length > 0) {
          this.selectedSubcategory = cat.subcategories[0];
        } else {
          this.selectedSubcategory = null;
        }
      }
    },

    selectSubcategory(subcategoryId: string): void {
      if (this.selectedCategory?.subcategories) {
        const sub = this.selectedCategory.subcategories.find(s => s.id === subcategoryId);
        if (sub) {
          this.selectedSubcategory = sub;
        }
      }
    },

    addToCart(item: MenuItem, quantity: number = 1): void {
      const existing = this.cart.find(
        c => c.menuItemId === item.id && (c.note ?? '') === '',
      );
      if (existing) {
        existing.quantity += quantity;
      } else {
        this.cart.push({
          menuItemId: item.id,
          name: item.name,
          unit: item.unit,
          price: item.price,
          price_display: item.price_display,
          quantity: quantity,
          note: ''
        });
      }
    },

    updateCartItem(itemId: string, quantity: number): void {
      const existing = this.cart.find(c => c.menuItemId === itemId);
      if (existing) {
        existing.quantity = quantity;
        if (existing.quantity <= 0) {
          this.removeFromCart(itemId);
        }
      }
    },

    updateCartItemNote(itemId: string, note: string): void {
      const existing = this.cart.find(c => c.menuItemId === itemId);
      if (existing) {
        existing.note = note;
      }
    },

    removeFromCart(itemId: string): void {
      this.cart = this.cart.filter(c => c.menuItemId !== itemId);
    },

    clearCart(): void {
      this.cart = [];
    },

    // Remove all cart items whose menuItemId is not a valid UUID.
    // Returns the names of removed items so the caller can notify the user.
    removeInvalidCartItems(): string[] {
      const invalid = this.cart.filter(c => !isValidUUID(c.menuItemId));
      this.cart = this.cart.filter(c => isValidUUID(c.menuItemId));
      return invalid.map(c => c.name);
    },

    // NV3: Service Request
    async submitServiceRequest(requestType: string, content?: string): Promise<void> {
      if (!this.session) return;

      const request: ServiceRequest = {
        id: `req-${Date.now()}`,
        sessionId: this.session.id,
        tableNumber: this.session.tableNumber,
        type: requestType as any,
        content: content || '',
        status: 'created',
        createdAt: new Date()
      };

      const result = await customerApiImpl.submitServiceRequest(request);
      this.serviceRequests.push(result);
      this.addNotification(`Đã gửi yêu cầu: ${this.translateRequestType(requestType)}`, 'success');
    },

    async cancelServiceRequest(requestId: string): Promise<void> {
      await customerApiImpl.updateServiceRequest(requestId, 'cancelled');
      const req = this.serviceRequests.find(r => r.id === requestId);
      if (req) {
        req.status = 'cancelled';
      }
      this.addNotification('Đã hủy yêu cầu phục vụ', 'info');
    },

    // NV4: Cart & Order
    async confirmOrder(): Promise<Order> {
      if (!this.session || this.cart.length === 0) {
        throw new Error('Giỏ hàng trống hoặc phiên làm việc chưa bắt đầu');
      }

      // Validate all cart items for UUID format
      const invalidItems = this.cart.filter(item => !isValidUUID(item.menuItemId));
      if (invalidItems.length > 0) {
        const names = invalidItems.map(i => i.name).join(', ');
        throw new Error(`Có ${invalidItems.length} món không hợp lệ trong giỏ hàng: ${names}`);
      }

      const subtotal = this.cartTotal;
      const charge = this.serviceCharge;
      const vatVal = this.vat;
      const grand = this.grandTotal;

      const order: Order = {
        id: `ord-${Date.now()}`,
        sessionId: this.session.id,
        tableNumber: this.session.tableNumber,
        items: [...this.cart],
        subtotal,
        serviceCharge: charge,
        vat: vatVal,
        discount: 0,
        total: grand,
        status: 'draft',
        createdAt: new Date()
      };

      const confirmedOrder = await customerApiImpl.createOrder(order);
      confirmedOrder.status = 'confirmed';
      this.orders.push(confirmedOrder);
      this.clearCart();
      this.addNotification('Đã gửi món vào bếp thành công!', 'success');
      return confirmedOrder;
    },

    async cancelOrder(orderId: string): Promise<void> {
      // Typically orders cannot be canceled after confirmation from tablet,
      // but let's provide client side action
      this.orders = this.orders.filter(o => o.id !== orderId);
      this.addNotification('Đã hủy order', 'info');
    },

    // NV5: History & Payment
    async loadOrderHistory(): Promise<Order[]> {
      if (!this.session) return [];
      const history = await customerApiImpl.getOrderHistory(this.session.id);
      this.orders = history;
      return history;
    },

    async requestPayment(): Promise<void> {
      if (!this.session) return;
      await customerApiImpl.requestPayment(this.session.id);
      this.session.status = 'waiting_payment';
      this.addNotification('Đã gửi yêu cầu thanh toán. Vui lòng đợi nhân viên.', 'success');
    },

    async requestInvoice(): Promise<void> {
      if (!this.session) return;
      await customerApiImpl.requestInvoice(this.session.id);
      this.addNotification('Đã gửi yêu cầu xuất hóa đơn đỏ.', 'success');
    },

    async submitFeedback(feedbackData: Omit<Feedback, 'id' | 'sessionId' | 'createdAt'>): Promise<void> {
      if (!this.session) return;

      const newFeedback: Feedback = {
        id: `fb-${Date.now()}`,
        sessionId: this.session.id,
        rating: feedbackData.rating,
        criteria: feedbackData.criteria,
        comment: feedbackData.comment || '',
        createdAt: new Date()
      };

      const result = await customerApiImpl.submitFeedback(newFeedback);
      this.feedback = result;
      this.addNotification('Cảm ơn đóng góp ý kiến của quý khách!', 'success');
    },

    // Session Management
    async endSession(): Promise<void> {
      if (this.session) {
        await customerApiImpl.releaseTable(this.session.id);
      }
      this.resetState();
    },

    resetState(): void {
      this.session = null;
      this.isAuthenticated = false;
      this.selectedBranchId = null;
      this.selectedAreaId = null;
      this.selectedTable = null;
      this.cart = [];
      this.orders = [];
      this.serviceRequests = [];
      this.feedback = null;
      this.currentView = 'home';
      this.notifications = [];
    },

    // UI Helpers
    addNotification(message: string, type: 'info' | 'success' | 'warning' | 'error' = 'info'): void {
      const id = `notif-${Date.now()}`;
      this.notifications.push({ id, message, type });
      setTimeout(() => {
        this.notifications = this.notifications.filter(n => n.id !== id);
      }, 4000);
    },

    translateRequestType(type: string): string {
      const types: Record<string, string> = {
        tissue: 'Lấy khăn giấy',
        bowl: 'Lấy chén bát sạch',
        sauce: 'Lấy nước chấm',
        ice: 'Lấy đá thêm',
        grill_change: 'Thay vỉ nướng',
        charcoal_change: 'Thêm than',
        request_bill: 'Thanh toán hóa đơn',
        call_waiter: 'Gọi nhân viên',
        other: 'Yêu cầu khác'
      };
      return types[type] || type;
    }
  },

  getters: {
    /**
     * Cart subtotal AFTER all rules: package-pricing (zero when in-pkg)
     * + lunch 50% discount are both baked into the stored `price`
     * field at add-to-cart time via the shared `@/utils/packageRules`
     * engine. So `cartTotal` collapses to `price * quantity`. Service
     * charge / VAT use the shared `computeTotals()` so the customer
     * and cashier previews agree to the đồng.
     */
    cartTotal: (state) => {
      return state.cart.reduce(
        (sum, item) => sum + Number(item.price ?? 0) * Number(item.quantity ?? 1),
        0,
      )
    },
    cartItemCount: (state) => {
      return state.cart.reduce((sum, item) => sum + item.quantity, 0);
    },
    serviceCharge(): number {
      return computeTotals(this.cartTotal).serviceCharge
    },
    vat(): number {
      return computeTotals(this.cartTotal).vat
    },
    grandTotal(): number {
      return computeTotals(this.cartTotal).total
    },
    activeServiceRequests: (state) => {
      return state.serviceRequests.filter(r => r.status !== 'completed' && r.status !== 'cancelled');
    },
    orderHistory: (state) => {
      return state.orders;
    }
  }
});

