  // Helper: Find table by code in areas
  const getTableByCode = (code: string): TableInfo | null => {
    for (const area of areas.value) {
      const found = area.tables.find(t => t.code === code);
      if (found) return found;
    }
    return null;
  };

  // Helper: Get area name of a table
  const getTableAreaName = (code: string): string => {
    for (const area of areas.value) {
      if (area.tables.some(t => t.code === code)) {
        return area.name;
      }
    }
    return 'Khu vực';
  };

  // Get active order for a table (or create an empty one)
  const getOrCreateOrder = (tableCode: string): TableOrder => {
    if (!tableOrders.value[tableCode]) {
      const table = getTableByCode(tableCode);
      const guestCount = table?.customerName ? 4 : 2; // Default mock guests count
      const now = new Date();
      const openTimeFormatted = now.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' }) + ' ' + now.toLocaleDateString('vi-VN');

      // Generate standard order number
      const randId = Math.floor(1000 + Math.random() * 9000);
      const orderNumber = `SF_0000${randId}`;

      tableOrders.value[tableCode] = {
        orderNumber,
        tableCode,
        customerName: table?.customerName || 'Khách vãng lai',
        guestCount,
        openedTime: table?.checkInTime || openTimeFormatted,
        items: []
      };
    }
    return tableOrders.value[tableCode];
  };

  // Select table for order and navigate
  const setSelectedTable = (tableCode: string | null) => {
    selectedTableCode.value = tableCode;
  };

  // Add Item to Table Order Cart
  const addOrderItem = (tableCode: string, item: MenuItem) => {
    const order = getOrCreateOrder(tableCode);
    const existing = order.items.find(i => i.id === item.id);
    if (existing) {
      existing.quantity++;
    } else {
      order.items.push({
        id: item.id,
        name: item.name,
        unit: item.unit,
        price: item.price,
        price_display: item.price_display,
        quantity: 1,
        category_id: item.category_id
      });
    }
  };

  // Update item quantity in cart
  const updateItemQuantity = (tableCode: string, itemId: string, change: number) => {
    const order = tableOrders.value[tableCode];
    if (!order) return;
    const item = order.items.find(i => i.id === itemId);
    if (item) {
      item.quantity += change;
      if (item.quantity <= 0) {
        order.items = order.items.filter(i => i.id !== itemId);
      }
    }
  };

  // Remove item from cart
  const removeOrderItem = (tableCode: string, itemId: string) => {
    const order = tableOrders.value[tableCode];
    if (!order) return;
    order.items = order.items.filter(i => i.id !== itemId);
  };

  return {
    areas,
    bookings,
    selectedTableCode,
    tableOrders,
    getTableByCode,
    getTableAreaName,
    getOrCreateOrder,
    setSelectedTable,
    addOrderItem,
    updateItemQuantity,
    removeOrderItem
  };
});

import { defineStore } from 'pinia';
import { ref } from 'vue';

export interface GrillRequest {
  id: string;
  status: 'pending' | 'completed' | string;
  [key: string]: any;
}

export interface PrepTask {
  id: string;
  completed: boolean;
  [key: string]: any;
}

// Kitchen Requisition Interface
export interface RequisitionItem {
  id: string;
  name: string;
  icon: string;
  unit: string;
  kitchenStock: number;
  mainStock: number;
  requestedQty: number;
  deliveredQty: number;
  status: 'pending' | 'approved' | 'rejected' | string;
  rejectionReason?: string;
  proposedSubstitute?: string;
}

export interface AuditLog {
  id: string;
  action: string;
  actor: string;
  timestamp: string;
}

export interface Requisition {
  id: string;
  date: string;
  timestamp: number;
  station: string;
  actor: string;
  priority: 'low' | 'medium' | 'high';
  status: 'pending' | 'substitute_proposed' | 'approved' | 'delivered' | 'rejected';
  notes: string;
  items: RequisitionItem[];
  rejectionReason?: string;
  auditLogs: AuditLog[];
  signatureImage?: string; // Signature Data URL
  cogsUpdated?: boolean;
}

export interface HandoverLogItem {
  id: string;
  name: string;
  icon: string;
  unit: string;
  theoretical: number;
  actual: number;
  diff: number;
}

export interface HandoverLog {
  id: string;
  date: string;
  shift: string;
  outgoingChef: string;
  incomingChef: string;
  fridgeTemp: number;
  freezerTemp: number;
  wasteNotes?: string;
  notes: string;
  items: HandoverLogItem[];
  signatureImage?: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  icon: string;
  unit: string;
  kitchenStock: number;
