      date: nowStr
    };

    handoverLogs.value.unshift(newLog);
    return newLog;
  };

  return {
    qcQueue,
    grillRequests,
    prepList,
    delayedTickets,
    showGrillRequestModal,
    isGrillPanelVisible,
    showPrepListModal,
    showHACCPModal,
    show86dModal,
    showDelayedOrdersModal,

    // Requisition State & Actions
    inventoryList,
    requisitions,
    addRequisition,
    updateRequisitionStatus,
    updateRequisitionItemDelivery,

    // Handover state & actions
    handoverLogs,
    addHandoverLog
  };
});

