      auditLogs: [
        { id: 'log-1', action: 'Tạo phiếu yêu cầu xuất kho', actor: 'Chef Luc', timestamp: '2026-06-26 10:30' }
      ]
    },
    {
      id: 'REQ-002',
      date: '2026-06-26 09:15',
