      station: 'Bếp Lẩu',
      actor: 'Chef Minh',
      priority: 'medium',
      status: 'delivered',
      notes: 'Hàng xuất định kỳ đầu ca.',
      items: [
        { id: 'inv-2', name: 'Nước lẩu Sukiyaki', icon: '🍲', unit: 'L', kitchenStock: 3, mainStock: 90, requestedQty: 20, deliveredQty: 20, status: 'approved' },
