        { id: 'log-6', action: 'Từ chối yêu cầu - Hết sườn', actor: 'Thủ kho Nam', timestamp: '2026-06-25 17:00' }
      ]
    },
    {
      id: 'REQ-004',
      date: '2026-06-27 11:00',
      timestamp: Date.now() - 1800000, // 30 mins ago
      station: 'Bếp Lẩu',
