      ...req,
      id,
      date: nowStr,
      timestamp: Date.now(),
      auditLogs: [
        { id: `log-${Date.now()}-1`, action: 'Tạo phiếu yêu cầu xuất kho', actor: req.actor, timestamp: nowStr }
      ]
    };

    requisitions.value.unshift(newReq);
    return newReq;
  };

